const item = $input.first().json;
let raw = item.output ?? item.text ?? item.output_text ?? (item.message && item.message.content) ?? item.content ?? '';
if (Array.isArray(raw)) {
  raw = raw.map(o => {
    if (typeof o === 'string') return o;
    if (o.content && Array.isArray(o.content)) return o.content.map(c => c.text ?? '').join('');
    return o.text ?? '';
  }).join('');
} else if (typeof raw === 'object' && raw !== null) {
  raw = JSON.stringify(raw);
}
raw = String(raw).trim();
const m = raw.match(/\{[\s\S]*\}/);
let plan;
try {
  plan = JSON.parse(m ? m[0] : raw);
} catch (e) {
  throw new Error('Sahne plani JSON olarak ayristirilmadi: ' + raw.slice(0, 300));
}
if (!plan.scenes || !Array.isArray(plan.scenes) || plan.scenes.length === 0) {
  throw new Error('Sahne plani bos geldi');
}
const scenes = plan.scenes.map((s, i) => ({
  n: s.n ?? i + 1,
  voiceover: String(s.voiceover ?? '').trim(),
  image_prompt: String(s.image_prompt ?? '').trim(),
  source: s.source === 'stock' ? 'stock' : 'ai',
  stock_query: String(s.stock_query ?? '').trim()
})).filter(s => s.voiceover && s.image_prompt);
if (scenes.length === 0) throw new Error('Gecerli sahne yok');
const t = plan.thumbnail ?? {};
const kapakText = String(t.text ?? '').trim();
let kapakPrompt = String(t.prompt ?? '').trim();
if (!kapakPrompt) kapakPrompt = scenes[0].image_prompt + ', dramatic close-up, high contrast, YouTube thumbnail composition';
if (kapakText) {
  kapakPrompt += '. Render the exact text "' + kapakText + '" inside the image as huge bold eye-catching title typography baked into the artwork, perfectly readable, high contrast against the background, professional YouTube thumbnail style. No other text, no watermarks.';
} else {
  kapakPrompt += '. No text in the image.';
}
return [{ json: { language: plan.language ?? 'en', voice: plan.voice ?? 'en-US-AndrewMultilingualNeural', kapak_text: kapakText, kapak_prompt: kapakPrompt, scenes } }];

const results = $input.all().map(i => i.json).filter(s => s.gorsel_url);
if (results.length === 0) return [{ json: { hata: true } }];
results.sort((a, b) => a.n - b.n);
const plan = $('Plan Ayristir').first().json;
const payload = {
  is_adi: 'is_' + $execution.id,
  voice: plan.voice,
  sahneler: results.map(s => ({ n: s.n, voiceover: s.voiceover, gorsel_url: s.gorsel_url, tur: s.tur }))
};
const b64 = Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
return [{ json: { hata: false, b64 } }];

const r = $input.first().json;
const scene = $('Sahne Dongusu').first().json;
const vids = Array.isArray(r.videos) ? r.videos : [];
let best = null;
for (const v of vids) {
  const file = (v.video_files || [])
    .filter(f => (f.width || 0) >= 1280 && (f.width || 0) <= 1920 && f.link)
    .sort((a, b) => (b.width || 0) - (a.width || 0))[0];
  if (!file) continue;
  const dur = v.duration || 0;
  if (!best || dur > best.duration) best = { duration: dur, link: file.link };
}
return [{ json: {
  n: scene.n,
  voiceover: scene.voiceover,
  gorsel_url: best ? best.link : '',
  tur: 'video',
  uretim_durumu: best ? 'completed' : 'stok_yok'
} }];

const out = String($input.first().json.stdout || '').trim().split('\n');
let sonuc = null;
for (let i = out.length - 1; i >= 0; i--) {
  try { sonuc = JSON.parse(out[i]); break; } catch (e) {}
}
if (!sonuc || !sonuc.video) throw new Error('Render ciktisi okunamadi: ' + out.slice(-3).join(' | '));
return [{ json: { video_yolu: sonuc.video, sure: sonuc.sure, sahne_sayisi: sonuc.sahne_sayisi } }];
